from collections import deque

def topo_sort(edges):
    """Topological sort of a directed graph.
    edges: iterable of (from_node, to_node) pairs
    Returns a list of nodes in topological order.
    Raises ValueError if the graph contains a cycle.
    """
    if not edges:
        return []

    # Deduplicate edges to handle multigraphs (parallel edges) correctly
    unique_edges = set()
    nodes = set()
    for e in edges:
        try:
            src, dst = e
        except Exception:
            raise ValueError("Each edge must be a (from_node, to_node) pair")
        unique_edges.add((src, dst))
        nodes.add(src)
        nodes.add(dst)

    if not nodes:
        return []

    # Build adjacency (deduplicated) and in-degree counts
    graph = {n: set() for n in nodes}
    in_degree = {n: 0 for n in nodes}

    for src, dst in unique_edges:
        # Early detect self-loop which is an immediate cycle
        if src == dst:
            raise ValueError("Graph contains a cycle")
        if dst not in graph[src]:
            graph[src].add(dst)
            in_degree[dst] += 1

    # Kahn's algorithm
    queue = deque(n for n in nodes if in_degree[n] == 0)
    result = []

    while queue:
        node = queue.popleft()
        result.append(node)
        for neighbor in graph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    if len(result) != len(nodes):
        raise ValueError("Graph contains a cycle")

    return result

