    Returns a list of nodes in topological order.
    Raises ValueError if the graph contains a cycle.
    """
    if not edges:
        # If no edges, return empty list only if there are no nodes
        # But if there are nodes with no edges, we should return them
        return []

    # Collect all nodes
    all_nodes = set()
    for src, dst in edges:
        all_nodes.add(src)
        all_nodes.add(dst)

    if not all_nodes:
        return []

    # Build adjacency list and in-degree count
    graph = {}
    in_degree = {}

    for node in all_nodes:
        graph[node] = []
        in_degree[node] = 0

    # Use a set to track unique edges to avoid counting parallel edges multiple times
    seen_edges = set()
    for src, dst in edges:
        if (src, dst) not in seen_edges:
            graph[src].append(dst)
            in_degree[dst] += 1
            seen_edges.add((src, dst))

    # Kahn's algorithm
    queue = [node for node in all_nodes if in_degree[node] == 0]
    result = []

    while queue:
        node = queue.pop(0)
        result.append(node)
        for neighbor in graph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
